const payload = $input.first().json.body || $input.first().json;
const event = payload.event || '';
if (event !== 'messages.upsert') return [];

const data = payload.data || {};
const key = data.key || {};
const msg = data.message || {};

// Ignore own messages
if (key.fromMe) return [];

const sender = (key.remoteJid || '').replace('@s.whatsapp.net', '');
const messageId = key.id || '';

// Extract content by type
let type = 'text';
let content = '';
if (msg.conversation) { content = msg.conversation; }
else if (msg.extendedTextMessage) { content = msg.extendedTextMessage.text || ''; }
else if (msg.audioMessage) { type = 'audio'; content = '[audio]'; }
else if (msg.imageMessage) { type = 'image'; content = msg.imageMessage.caption || '[image]'; }
else if (msg.documentMessage) { type = 'document'; content = msg.documentMessage.fileName || '[document]'; }

// Filter: must start with /claude OR be permission reply OR be audio/image reply
const claudePrefix = /^\/claude\b/i;
const permReply = /^\s*(y|yes|n|no|sim|s)\s+[a-km-z]{5}\s*$/i;
const hasContext = msg.audioMessage?.contextInfo || msg.imageMessage?.contextInfo;

if (type === 'text' && !claudePrefix.test(content.trim()) && !permReply.test(content)) {
  return [];
}
if ((type === 'audio' || type === 'image') && !hasContext && !claudePrefix.test(content.trim())) {
  return [];
}

// Strip /claude prefix
let project = 'default';
if (claudePrefix.test(content.trim())) {
  content = content.trim().replace(/^\/claude\s*/i, '');
  // Project routing: first word after /claude can be a project name
  // Add your project names here if needed
}

// Store in static data queue
const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) staticData.queue = {};
if (!staticData.queue[project]) staticData.queue[project] = [];

staticData.queue[project].push({
  sender, message_id: messageId, type, content,
  raw: data, timestamp: Date.now()
});

return [{ json: { status: 'queued', sender, project } }];

const query = $input.first().json.query || {};
const project = query.project || 'default';
const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) staticData.queue = {};

const messages = [];
const cutoff = Date.now() - 3600000; // 1h TTL

// Drain project queue
if (staticData.queue[project]) {
  while (staticData.queue[project].length > 0) {
    const msg = staticData.queue[project].shift();
    if (msg.timestamp > cutoff) messages.push(msg);
  }
}

// Also drain default queue if different project
if (project !== 'default' && staticData.queue['default']) {
  while (staticData.queue['default'].length > 0) {
    const msg = staticData.queue['default'].shift();
    if (msg.timestamp > cutoff) messages.push(msg);
  }
}

return [{ json: { messages } }];
